import React, { useState } from 'react';
import './UPIAutoSync.css';

function UPIAutoSync({ onBack }) {
  const [smsText, setSmsText] = useState('');
  const [transactions, setTransactions] = useState([]);
  const [analysis, setAnalysis] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [activeTab, setActiveTab] = useState('input'); // input, transactions, analysis

  const handleParseSMS = async () => {
    if (!smsText.trim()) {
      setError('Please enter SMS messages');
      return;
    }

    setLoading(true);
    setError(null);

    try {
      // Split SMS by newlines (each SMS on a new line)
      const smsMessages = smsText
        .split('\n')
        .filter(sms => sms.trim().length > 0);

      const response = await fetch('/api/upi/parse-sms', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ sms_messages: smsMessages })
      });

      if (response.ok) {
        const data = await response.json();
        setTransactions(data.transactions);
        setActiveTab('transactions');
      } else {
        setError('Failed to parse SMS messages');
      }
    } catch (err) {
      setError('Error connecting to server');
    } finally {
      setLoading(false);
    }
  };

  const handleAnalyzeSpending = async () => {
    if (transactions.length === 0) {
      setError('No transactions to analyze');
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const response = await fetch('/api/upi/analyze-spending', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ transactions })
      });

      if (response.ok) {
        const data = await response.json();
        setAnalysis(data);
        setActiveTab('analysis');
      } else {
        setError('Failed to analyze spending');
      }
    } catch (err) {
      setError('Error connecting to server');
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (value) => {
    return `₹${value.toLocaleString('en-IN', { maximumFractionDigits: 0 })}`;
  };

  const renderInputTab = () => (
    <div className="upi-input-section">
      <div className="upi-instructions">
        <h3>📱 How to Use UPI Auto-Sync</h3>
        <ol>
          <li>Copy your UPI transaction SMS messages</li>
          <li>Paste them in the text area below (one SMS per line)</li>
          <li>Click "Parse SMS" to extract transactions</li>
          <li>View detailed spending analysis</li>
        </ol>
        
        <div className="supported-apps">
          <h4>Supported UPI Apps:</h4>
          <div className="app-badges">
            <span className="app-badge">Google Pay</span>
            <span className="app-badge">PhonePe</span>
            <span className="app-badge">Paytm</span>
            <span className="app-badge">Amazon Pay</span>
            <span className="app-badge">BHIM</span>
            <span className="app-badge">WhatsApp Pay</span>
          </div>
        </div>
      </div>

      <div className="sms-input-container">
        <label>Paste Your UPI SMS Messages:</label>
        <textarea
          className="sms-textarea"
          value={smsText}
          onChange={(e) => setSmsText(e.target.value)}
          placeholder="Example:
Rs.500 debited from your account to Swiggy via Google Pay on 08-Feb-2026
Rs.1200 paid to Amazon via PhonePe UPI on 07-Feb-2026
Rs.350 sent to zomato@paytm using Paytm on 06-Feb-2026"
          rows={15}
        />
        
        <div className="input-actions">
          <button 
            className="parse-button" 
            onClick={handleParseSMS}
            disabled={loading || !smsText.trim()}
          >
            {loading ? '⏳ Parsing...' : '🔍 Parse SMS Messages'}
          </button>
          <button className="clear-button" onClick={() => setSmsText('')}>
            Clear
          </button>
        </div>
      </div>
    </div>
  );

  const renderTransactionsTab = () => (
    <div className="upi-transactions-section">
      <div className="transactions-header">
        <h3>📊 Extracted Transactions ({transactions.length})</h3>
        <button className="analyze-button" onClick={handleAnalyzeSpending}>
          📈 Analyze Spending
        </button>
      </div>

      <div className="transactions-list">
        {transactions.map((trans, index) => (
          <div key={index} className={`transaction-card ${trans.type}`}>
            <div className="trans-header">
              <span className="trans-amount">
                {formatCurrency(trans.amount)}
              </span>
              <span className={`trans-type ${trans.type}`}>
                {trans.type === 'debit' ? '↓ Paid' : '↑ Received'}
              </span>
            </div>
            
            <div className="trans-details">
              {trans.merchant && (
                <div className="trans-detail">
                  <span className="detail-label">Merchant:</span>
                  <span className="detail-value">{trans.merchant}</span>
                </div>
              )}
              {trans.upi_app && (
                <div className="trans-detail">
                  <span className="detail-label">UPI App:</span>
                  <span className="detail-value">{trans.upi_app}</span>
                </div>
              )}
              {trans.upi_id && (
                <div className="trans-detail">
                  <span className="detail-label">UPI ID:</span>
                  <span className="detail-value">{trans.upi_id}</span>
                </div>
              )}
              {trans.date && (
                <div className="trans-detail">
                  <span className="detail-label">Date:</span>
                  <span className="detail-value">{trans.date}</span>
                </div>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderAnalysisTab = () => {
    if (!analysis) return null;

    const currentMonth = analysis.current_month;

    return (
      <div className="upi-analysis-section">
        <h2>📊 Monthly Spending Analysis</h2>

        {/* Summary Cards */}
        <div className="analysis-summary-cards">
          <div className="analysis-card total-spent">
            <div className="card-icon">💸</div>
            <div className="card-content">
              <p className="card-label">Total Spent</p>
              <p className="card-value">{formatCurrency(currentMonth.total_spent)}</p>
            </div>
          </div>

          <div className="analysis-card total-received">
            <div className="card-icon">💰</div>
            <div className="card-content">
              <p className="card-label">Total Received</p>
              <p className="card-value">{formatCurrency(currentMonth.total_received)}</p>
            </div>
          </div>

          <div className="analysis-card net-balance">
            <div className="card-icon">⚖️</div>
            <div className="card-content">
              <p className="card-label">Net Balance</p>
              <p className="card-value">{formatCurrency(currentMonth.net_balance)}</p>
            </div>
          </div>

          <div className="analysis-card daily-avg">
            <div className="card-icon">📅</div>
            <div className="card-content">
              <p className="card-label">Daily Average</p>
              <p className="card-value">{formatCurrency(currentMonth.daily_average)}</p>
            </div>
          </div>
        </div>

        {/* Insights */}
        {currentMonth.insights && currentMonth.insights.length > 0 && (
          <div className="insights-card">
            <h3>💡 Key Insights</h3>
            <ul className="insights-list">
              {currentMonth.insights.map((insight, index) => (
                <li key={index}>{insight}</li>
              ))}
            </ul>
          </div>
        )}

        {/* UPI App Analysis */}
        {currentMonth.upi_app_analysis && Object.keys(currentMonth.upi_app_analysis).length > 0 && (
          <div className="upi-apps-card">
            <h3>📱 UPI App Usage</h3>
            <div className="upi-apps-grid">
              {Object.entries(currentMonth.upi_app_analysis).map(([app, data]) => (
                <div key={app} className="upi-app-item">
                  <div className="app-name">{app}</div>
                  <div className="app-stats">
                    <div className="stat">
                      <span className="stat-label">Spent:</span>
                      <span className="stat-value">{formatCurrency(data.total_spent)}</span>
                    </div>
                    <div className="stat">
                      <span className="stat-label">Transactions:</span>
                      <span className="stat-value">{data.transaction_count}</span>
                    </div>
                    <div className="stat">
                      <span className="stat-label">Avg:</span>
                      <span className="stat-value">{formatCurrency(data.average_transaction)}</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Category Analysis */}
        {currentMonth.category_analysis && Object.keys(currentMonth.category_analysis).length > 0 && (
          <div className="categories-card">
            <h3>🏷️ Spending by Category</h3>
            <div className="categories-list">
              {Object.entries(currentMonth.category_analysis)
                .sort((a, b) => b[1].amount - a[1].amount)
                .map(([category, data]) => (
                  <div key={category} className="category-item">
                    <div className="category-header">
                      <span className="category-name">{category}</span>
                      <span className="category-amount">{formatCurrency(data.amount)}</span>
                    </div>
                    <div className="category-bar">
                      <div 
                        className="category-fill" 
                        style={{ width: `${data.percentage}%` }}
                      ></div>
                    </div>
                    <div className="category-details">
                      <span>{data.count} transactions</span>
                      <span>{data.percentage.toFixed(1)}%</span>
                    </div>
                  </div>
                ))}
            </div>
          </div>
        )}

        {/* Top Merchants */}
        {currentMonth.top_merchants && currentMonth.top_merchants.length > 0 && (
          <div className="merchants-card">
            <h3>🏪 Top Merchants</h3>
            <div className="merchants-list">
              {currentMonth.top_merchants.map((merchant, index) => (
                <div key={index} className="merchant-item">
                  <span className="merchant-rank">#{index + 1}</span>
                  <span className="merchant-name">{merchant.name}</span>
                  <span className="merchant-amount">{formatCurrency(merchant.amount)}</span>
                  <span className="merchant-count">{merchant.transactions} txns</span>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="upi-auto-sync">
      <div className="upi-header">
        <button className="back-button" onClick={onBack}>
          ← Back to Dashboard
        </button>
        <h1>📱 UPI Auto-Sync</h1>
        <p className="subtitle">Automatic UPI transaction analysis from SMS</p>
      </div>

      {error && (
        <div className="error-message">
          ⚠️ {error}
        </div>
      )}

      <div className="upi-tabs">
        <button 
          className={`tab ${activeTab === 'input' ? 'active' : ''}`}
          onClick={() => setActiveTab('input')}
        >
          📝 Input SMS
        </button>
        <button 
          className={`tab ${activeTab === 'transactions' ? 'active' : ''}`}
          onClick={() => setActiveTab('transactions')}
          disabled={transactions.length === 0}
        >
          📊 Transactions ({transactions.length})
        </button>
        <button 
          className={`tab ${activeTab === 'analysis' ? 'active' : ''}`}
          onClick={() => setActiveTab('analysis')}
          disabled={!analysis}
        >
          📈 Analysis
        </button>
      </div>

      <div className="upi-content">
        {activeTab === 'input' && renderInputTab()}
        {activeTab === 'transactions' && renderTransactionsTab()}
        {activeTab === 'analysis' && renderAnalysisTab()}
      </div>
    </div>
  );
}

export default UPIAutoSync;
